Here's a function in JavaScript that takes an array of 5 numbers as input and checks if any of the numbers is a valid prime number. If it is, the function prints the number to the console:
```javascript
function checkPrimeNumbers(numbers) {
  for (let number of numbers) {
    if (isPrime(number)) {
      console.log(number);
      break;
    }
  }
}

function isPrime(number) {
  for (let i = 2; i < number; i++) {
    if (number % i === 0) {
      return false;
    }
  }
  return true;
}

